            { group: 'Data & Security Infrastructure', items: ['Native connectors for every DB (PostgreSQL, MongoDB, Snowflake, Firebase)', 'Direct REST, GraphQL, and SOAP API integration', 'Absolute Enterprise security protocols (On-premise deployment capabilities)', 'Granular Single Sign-On (SSO) and Role-Based Access Control (RBAC)'] }
