            { group: 'AI & Presentation Suite', items: ['Rows AI Analyst (natural language querying of datasets)', 'Deep OpenAI integration directly inside specific cells (=OPENAI format)', 'High-end aesthetic publishing (turning spreadsheets into beautiful websites)', 'Instant charting and visualization layers'] }
